VALUES
  ('aboriginal-f0899a01-moex-00317', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '人民依據政府資訊公開法向政府機關申請提供政府資訊，下列敘述何者錯誤？', '["非任何外國人都有資格提出申請", "申請書中應敘明申請政府資訊之用途", "以申請人為主張或維護其法律上利益有必要者為限，准予提供相關資訊", "申請提供之資訊若涉及特定個人之權益者，原則上應先以書面通知該特定個人表示意見"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00318', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '有關行政程序之進行，下列敘述何者正確？', '["行政機關調查證據時，僅就有利於當事人之部分注意之", "行政機關為瞭解事實真相，應實施勘驗", "行政機關基於調查事實及證據之必要，僅得要求當事人提供必要之文書、資料或物品，不及於第三人", "行政機關得自行選定適當之人擔任鑑定人，提供書面鑑定"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00319', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政程序法上當事人之規定，下列敘述何者錯誤？', '["代理人有2人以上者，均得單獨代理當事人", "選定或指定當事人有2人以上時，均得單獨為全體為行政程序行為", "代理人之代理權因本人死亡或其行政程序行為能力喪失而消滅", "無行政程序行為能力者，應由其法定代理人代為行政程序行為"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00320', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政程序上之聽證，下列敘述何者正確？', '["法規明文規定應舉行聽證者，得以公聽會代之", "原則上應公開以言詞為之", "無須遵守之法定程序", "經聽證程序作成之行政處分，應循訴願、行政訴訟程序救濟"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00321', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '民間汽車修護廠受主管機關委託辦理汽車檢驗，若不服其檢驗結果不合格之認定時，應如何救濟？', '["提起申訴", "提起民事訴訟", "逕行提起行政訴訟", "提起訴願"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00322', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於訴願制度設置之目的，下列何者不屬之？', '["促進行政機關間之和諧", "紓解法院負擔", "落實憲法訴願權之保障", "提供行政機關自我審查之機會"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00323', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '訴願人對於確定訴願決定，向原訴願決定機關申請再審期間，自訴願決定確定時起算，至遲應於幾日 內提起？', '["10日", "20日", "30日", "60日"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00324', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '甲申請之建造執照經核准後，若位於該建地旁邊之乙認為，該建照之核發損害其權利，遂依法提起訴 願。若乙提起訴願後，主管機關因甲未履行負擔，而將原建造執照廢止，此時訴願機關應為何種訴願 決定？', '["以訴願有理由，再行撤銷該處分", "訴願不受理", "以訴願無理由，將訴願駁回", "確認該建造執照之處分違法"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00325', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '關於行政訴訟法規定之重新審理，下列敘述何者錯誤？', '["開始重新審理之裁定確定後，應即回復原訴訟程序，依其審級更為審判", "開始重新審理之裁定確定後，聲請人即為原告之共同訴訟人", "聲請重新審理原則上無停止原確定判決執行之效力", "專屬為判決之原行政法院管轄"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL),
  ('aboriginal-f0899a01-moex-00326', 'aboriginal-f0899a01', 'aboriginal-f0899a01-moex-112-d1a761c9', 'sub-aboriginal-f0899a01-03', NULL, 'single_choice', '依行政訴訟法規定，有關簡易行政訴訟之敘述，下列何者正確？', '["簡易訴訟事件徵收裁判費新臺幣3,000元", "稅捐課徵事件，核課之稅額在新臺幣60萬元以下者適用簡易訴訟程序", "對於簡易訴訟之第二審判決不得上訴", "簡易訴訟之提起不得以言詞為之"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:37:33+00:00", "source_pdf_sha1": "3e47e40b33a1", "answer_pdf_sha1": "28e21bfe5d60", "source_family": "moex-gov-tw", "moex": {"exam_code": "112150", "c": "608", "s": "0603", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "行政法概要", "year": "112", "exam_name": "112年公務人員特種考試外交領事人員及外交行政人員考試、國際經濟商務人員考試、民航人員考試、原住民族考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "aboriginal", "civil_category": "法警"}'::jsonb, NULL)
